import { Link } from "react-router-dom";

const Sidebar = () => {
  return (
    <div
      style={{
        width: "240px",
        height: "100vh",
        background: "#1e293b",
        color: "white",
        padding: "25px",
      }}
    >
      <h2 style={{ marginBottom: "40px" }}>URMS</h2>

      <div style={{ display: "flex", flexDirection: "column", gap: "20px" }}>
        <Link to="/dashboard" style={{ color: "white" }}>Dashboard</Link>

        <Link to="/resources" style={{ color: "white" }}>Browse Resources</Link>

        <Link to="/my-resources" style={{ color: "white" }}>My Resources</Link>

        <Link to="/requests" style={{ color: "white" }}>Request History</Link>

        <Link to="/notifications" style={{ color: "white" }}>Notifications</Link>

        <Link to="/profile" style={{ color: "white" }}>Profile</Link>
      </div>
    </div>
  );
};

export default Sidebar;
